import{_ as t,o as e,c as i,a5 as r}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"学习记录 #0004：数字控制基础——从连续到离散","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0004：数字控制基础——从连续到离散","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第4课 — 数字控制基础——从连续到离散 **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0004-digital-control-basics.md","filePath":"content/power/archive/old-learning-records/0004-digital-control-basics.md","lastUpdated":null}'),l={name:"content/power/archive/old-learning-records/0004-digital-control-basics.md"};function o(n,a,s,c,d,g){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="学习记录-0004-数字控制基础——从连续到离散" tabindex="-1">学习记录 #0004：数字控制基础——从连续到离散 <a class="header-anchor" href="#学习记录-0004-数字控制基础——从连续到离散" aria-label="Permalink to &quot;学习记录 #0004：数字控制基础——从连续到离散&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第4课 — 数字控制基础——从连续到离散 <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>Tustin变换是首选</strong>：无条件稳定+二阶精度O(Ts²)，前向欧拉可能将稳定系统变不稳定</li><li><strong>PI离散化核心公式</strong>：u[k] = u[k-1] + b0<em>e[k] + b1</em>e[k-1]，b0=Kp+KiTs/2, b1=-Kp+KiTs/2</li><li><strong>增量式PI天然抗积分饱和</strong>：输出增量，限幅截断即可，不需要额外的Clamping逻辑</li><li><strong>控制延迟是隐形杀手</strong>：ADC在ZERO触发+影子寄存器下个ZERO装载 = 2个开关周期延迟，相位滞后72°@2kHz</li><li><strong>最优时序</strong>：PEAK点触发ADC → ISR计算 → ZERO点影子装载，延迟≈0.5Tsw</li><li><strong>带宽法整定</strong>：内环带宽≥5×外环带宽，零极点对消+穿越频率=期望带宽</li></ol><h2 id="代码要点" tabindex="-1">代码要点 <a class="header-anchor" href="#代码要点" aria-label="Permalink to &quot;代码要点&quot;">​</a></h2><ul><li>位置式PI：需要条件积分（Clamping）抗饱和</li><li>增量式PI：b0/b1预计算，差分方程一步到位，限幅截断</li><li>初始化：b0=Kp+KiTs/2, b1=-Kp+KiTs/2</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 双更新模式（Double Update）的ePWM寄存器怎么配置？</li><li>[ ] 电压环被控对象模型为什么简化为1/(Cs)？负载电阻的影响呢？</li><li>[ ] 反计算法（Back-calculation）抗积分饱和的具体实现？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第5课：锁相环（PLL）技术</p>',10)])])}const u=t(l,[["render",o]]);export{p as __pageData,u as default};
